#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1 



void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void
init(int argc, char** argv)
{
	if(argc==4){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
                pyramid_height=atoi(argv[3]);
	}else{
                printf("Usage: dynproc row_len col_len pyramid_height\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{
    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blockCols = (cols + border * 2 + small_block_cols - 1) / small_block_cols;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blockCols; bx++) {
        int prev[BLOCK_SIZE];
        int result_buf[BLOCK_SIZE];

        int tx = 0; 

        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        // Load initial data for this block
        for (int local_idx = 0; local_idx < BLOCK_SIZE; local_idx++) {
            int xidx = blkX + local_idx;
            if (IN_RANGE(xidx, 0, cols - 1)) {
                prev[local_idx] = gpuSrc[xidx];
            } else {
                prev[local_idx] = 0;
            }
        }

        bool computed = false;

        for (int i = 0; i < iteration; i++) { 
            computed = false;

            int start_tx = i + 1;
            int end_tx = BLOCK_SIZE - i - 2;

            for (int tx = start_tx; tx <= end_tx; tx++) {
                if (tx >= validXmin && tx <= validXmax) {
                    computed = true;
                    int W = tx - 1;
                    int E = tx + 1;

                    if (W < validXmin) W = validXmin;
                    if (E > validXmax) E = validXmax;

                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);

                    int xidx = blkX + tx;
                    int index = cols * (startStep + i) + xidx;
                    result_buf[tx] = shortest + gpuWall[index];
                }
            }

            if (i == iteration - 1)
                break;

            if (computed) {
                for (int tx = start_tx; tx <= end_tx; tx++) {
                    if (tx >= validXmin && tx <= validXmax) {
                        prev[tx] = result_buf[tx];
                    }
                }
            }
        }

        // Write results back
        int final_start = iteration - 1 + 1;
        int final_end = BLOCK_SIZE - (iteration - 1) - 2;

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            if (IN_RANGE(xidx, 0, cols - 1)) {
                if (tx >= final_start && tx <= final_end && tx >= validXmin && tx <= validXmax) {
                    gpuResults[xidx] = result_buf[tx];
                }
            }
        }
    }
}

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;
    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;

        dynproc_kernel(
            MIN(pyramid_height, rows - t - 1), 
            gpuWall, gpuResult[src], gpuResult[dst],
            cols, rows, t, borderCols);
    }
    return dst;
}

int main(int argc, char** argv)
{
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height) * HALO * 2;
    int blockCols = cols / smallBlockCol + ((cols % smallBlockCol == 0) ? 0 : 1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int *gpuWall, *gpuResult[2];
    int size = rows * cols;

    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];

    for(int i=0; i<cols; i++) gpuResult[0][i] = data[i];

    gpuWall = new int[size - cols];
    for(int i=0; i<size-cols; i++) gpuWall[i] = data[cols + i];

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, \
	 pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    for(int i=0; i<cols; i++) result[i] = gpuResult[final_ret][i];

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] gpuWall;
    delete [] gpuResult[0];
    delete [] gpuResult[1];

    delete [] data;
    delete [] wall;
    delete [] result;

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
